// ── Contact ───────────────────────────────────────────────────────────────────
function ContactSection() {
  const [form, setForm] = useState({ name: "", email: "", subject: "", message: "" });
  const [sent, setSent] = useState(false);
  const [focus, setFocus] = useState(null);
  const [submitHover, setSubmitHover] = useState(false);
  const inputStyle = (f) => ({ ...s.input, borderColor: focus === f ? "#cc0000" : "#ddd", outline: "none", boxShadow: focus === f ? "0 0 0 3px rgba(204,0,0,0.1)" : "none" });
  return (
    <section style={s.section}>
      <div style={s.sectionHeader}>
        <h2 style={s.sectionTitle}>CONTACT US</h2>
        <p style={s.sectionSub}>We'd love to hear from you. Reach out anytime.</p>
      </div>
      <div style={s.contactGrid}>
        <div style={s.contactLeft}>
          {[{ icon: "📧", label: "Email", val: "nepal@nike.com" }, { icon: "📞", label: "Phone", val: "+977 1-4200100" }, { icon: "🕐", label: "Hours", val: "Sun–Fri 10am–6pm NPT" }, { icon: "💬", label: "Live Chat", val: "Available on nike.com.np" }].map((c, i) => (
            <div key={i} style={s.contactCard}><span style={s.contactIcon}>{c.icon}</span><div><p style={s.contactLabel}>{c.label}</p><p style={s.contactVal}>{c.val}</p></div></div>
          ))}
        </div>
        <div style={s.contactRight}>
          {sent ? (
            <div style={s.successBox}><span style={{ fontSize: 48 }}>✅</span><h3 style={{ fontSize: 22, fontWeight: 800, marginTop: 12 }}>Message Sent!</h3><p style={{ color: "#555", marginTop: 8 }}>We'll get back to you within 24 hours.</p><button style={{ ...s.shopBtn, marginTop: 20, background: "#cc0000" }} onClick={() => setSent(false)}>Send Another</button></div>
          ) : (
            <div style={s.formBox}>
              <div style={s.formRow}>
                <input placeholder="Your Name" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} style={inputStyle("name")} onFocus={() => setFocus("name")} onBlur={() => setFocus(null)} />
                <input placeholder="Email Address" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} style={inputStyle("email")} onFocus={() => setFocus("email")} onBlur={() => setFocus(null)} />
              </div>
              <input placeholder="Subject" value={form.subject} onChange={e => setForm({ ...form, subject: e.target.value })} style={{ ...inputStyle("subject"), width: "100%", marginBottom: 16 }} onFocus={() => setFocus("subject")} onBlur={() => setFocus(null)} />
              <textarea placeholder="Your message..." value={form.message} onChange={e => setForm({ ...form, message: e.target.value })} style={{ ...inputStyle("message"), width: "100%", height: 130, resize: "vertical", fontFamily: "inherit" }} onFocus={() => setFocus("message")} onBlur={() => setFocus(null)} />
              <button style={{ ...s.shopBtn, marginTop: 16, width: "100%", background: submitHover ? "#a00000" : "#cc0000", transform: submitHover ? "translateY(-2px)" : "translateY(0)" }}
                onClick={() => { if (form.name && form.email && form.message) setSent(true); }}
                onMouseEnter={() => setSubmitHover(true)} onMouseLeave={() => setSubmitHover(false)}>Send Message →</button>
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

// ── Main App ──────────────────────────────────────────────────────────────────
export default function App() {
  const [activePage, setActivePage] = useState("Home");
  const [hoveredNav, setHoveredNav] = useState(null);
  const [loginHover, setLoginHover] = useState(false);
  const [loggedInUser, setLoggedInUser] = useState(null);

  const navItems = ["Menu", "Location", "About", "Contact"];

  const handleLogin = (username) => {
    setLoggedInUser(username);
    setActivePage("Dashboard");
  };

  const handleLogout = () => {
    setLoggedInUser(null);
    setActivePage("Home");
  };

  // Full-page views (no navbar)
  if (activePage === "Login") {
    return <LoginPage onLogin={handleLogin} onBack={() => setActivePage("Home")} />;
  }
  if (activePage === "Dashboard") {
    return <Dashboard username={loggedInUser} onLogout={handleLogout} />;
  }

  const renderPage = () => {
    switch (activePage) {
      case "Menu": return <MenuSection />;
      case "Location": return <LocationSection />;
      case "About": return <AboutSection />;
      case "Contact": return <ContactSection />;
      default: return <HeroSection onNav={setActivePage} />;
    }
  };

  return (
    <div style={s.page}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@700;900&family=Barlow:wght@400;600&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: 'Barlow', sans-serif; }
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: #f1f1f1; }
        ::-webkit-scrollbar-thumb { background: #cc0000; border-radius: 3px; }
      `}</style>

      <nav style={s.nav}>
        <div style={{ cursor: "pointer" }} onClick={() => setActivePage("Home")}><NikeLogo /></div>
        <ul style={s.navLinks}>
          {navItems.map(item => (
            <li key={item}
              style={{ ...s.navItem, color: activePage === item || hoveredNav === item ? "#cc0000" : "#111", borderBottom: activePage === item || hoveredNav === item ? "2px solid #cc0000" : "2px solid transparent" }}
              onMouseEnter={() => setHoveredNav(item)} onMouseLeave={() => setHoveredNav(null)}
              onClick={() => setActivePage(item)}>{item}</li>
          ))}
        </ul>
        <button
          style={{ ...s.loginBtn, background: loginHover ? "#a00000" : "#cc0000", transform: loginHover ? "scale(1.05)" : "scale(1)" }}
          onMouseEnter={() => setLoginHover(true)} onMouseLeave={() => setLoginHover(false)}
          onClick={() => setActivePage("Login")}
        >login</button>
      </nav>

      {activePage !== "Home" && (
        <div style={s.breadcrumb}>
          <span style={{ cursor: "pointer", color: "#cc0000", fontWeight: 700 }} onClick={() => setActivePage("Home")}>Home</span>
          <span style={{ margin: "0 8px", color: "#bbb" }}>/</span>
          <span style={{ color: "#111", fontWeight: 700 }}>{activePage}</span>
        </div>
      )}

      {renderPage()}

      <footer style={s.footer}>
        <div style={s.footerInner}>
          <NikeLogo color="white" />
          <p style={s.footerText}>© 2024 Nike, Inc. All Rights Reserved.</p>
          <div style={{ display: "flex", alignItems: "center", gap: 24 }}>
            {navItems.map(item => (
              <span key={item} style={s.footerLink} onClick={() => setActivePage(item)}>{item}</span>
            ))}
            <img
              src={NIKE_DARK_LOGO_SRC}
              alt="Nike"
              style={{ height: 48, width: "auto", objectFit: "contain", mixBlendMode: "screen", borderRadius: 6 }}
            />
          </div>
        </div>
      </footer>
    </div>
  );
}

